payload.text:
To modernize the "Add Profile/Lead" form, I will update `components/LeadModal.tsx` to feature a cleaner design with curved edges (`rounded-3xl`), soft shadows (`shadow-2xl`), a subtle background gradient, and improved typography. The form inputs will also be updated to match the rounded aesthetic with icons for better visual cues.

# Updated files:

## components/LeadModal.tsx

Redesigned the modal with a modern, beautiful aesthetic featuring curved edges, shadows, and enhanced input styling.

```tsx
import React, { useState } from 'react';
import { Lead } from '../types';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { X, Wand2, User, Mail, Phone, Globe, FileText, Sparkles } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

interface LeadModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (lead: Omit<Lead, 'id' | 'createdAt'>) => void;
}

export const LeadModal: React.FC<LeadModalProps> = ({ isOpen, onClose, onSave }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    source: 'Manual' as const,
    status: 'New' as const,
    notes: '',
  });

  const [isGenerating, setIsGenerating] = useState(false);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
    onClose();
  };

  const generateEnrichment = async () => {
    if (!formData.name && !formData.notes) return;

    setIsGenerating(true);
    try {
      if (!process.env.API_KEY) {
        // Mock if no key
        await new Promise(r => setTimeout(r, 1000));
        setFormData(prev => ({
          ...prev,
          notes: prev.notes + "\n(AI Insight): Likely interested in enterprise plan based on email domain."
        }));
        return;
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Given the partial lead info: Name: ${formData.name}, Current Notes: ${formData.notes}. Generate a brief, professional suggestion for a follow-up approach.`,
      });

      const insight = response.text;
      setFormData(prev => ({
        ...prev,
        notes: (prev.notes ? prev.notes + '\n\n' : '') + `AI Insight: ${insight}`
      }));
    } catch (error) {
      console.error("AI generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 transition-all duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in-95 duration-300 border border-white/20 relative">

        {/* Decorative Header Background */}
        <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-br from-emerald-500/10 via-teal-500/5 to-transparent pointer-events-none" />

        <div className="flex justify-between items-center p-8 pb-2 relative z-10">
          <div>
            <h2 className="text-2xl font-bold text-slate-900 tracking-tight">New Profile</h2>
            <p className="text-slate-500 text-sm mt-1">Add a new lead to your CRM pipeline.</p>
          </div>
          <button 
            onClick={onClose} 
            className="text-slate-400 hover:text-slate-900 hover:bg-slate-100/80 p-2 rounded-full transition-all duration-200"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 relative z-10">

          <div className="space-y-4">
             {/* Name */}
            <div className="relative group">
                <div className="absolute left-3 top-[2.4rem] text-slate-400 group-focus-within:text-emerald-500 transition-colors">
                    <User className="w-4 h-4" />
                </div>
                <Input 
                    label="Full Name" 
                    placeholder="Jane Doe" 
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    required
                    className="pl-9 rounded-xl border-slate-200 focus:border-emerald-500 focus:ring-emerald-500/20 transition-all bg-slate-50/50 focus:bg-white"
                />
            </div>

            <div className="grid grid-cols-2 gap-4">
                {/* Email */}
                <div className="relative group">
                    <div className="absolute left-3 top-[2.4rem] text-slate-400 group-focus-within:text-emerald-500 transition-colors">
                        <Mail className="w-4 h-4" />
                    </div>
                    <Input 
                        label="Email" 
                        type="email"
                        placeholder="jane@company.com" 
                        value={formData.email}
                        onChange={(e) => setFormData({...formData, email: e.target.value})}
                        required
                        className="pl-9 rounded-xl border-slate-200 focus:border-emerald-500 focus:ring-emerald-500/20 transition-all bg-slate-50/50 focus:bg-white"
                    />
                </div>

                {/* Phone */}
                <div className="relative group">
                    <div className="absolute left-3 top-[2.4rem] text-slate-400 group-focus-within:text-emerald-500 transition-colors">
                        <Phone className="w-4 h-4" />
                    </div>
                    <Input 
                        label="Phone" 
                        placeholder="+1 (555) 000-0000" 
                        value={formData.phone}
                        onChange={(e) => setFormData({...formData, phone: e.target.value})}
                        className="pl-9 rounded-xl border-slate-200 focus:border-emerald-500 focus:ring-emerald-500/20 transition-all bg-slate-50/50 focus:bg-white"
                    />
                </div>
            </div>

            {/* Source */}
            <div className="relative group">
                <label className="block text-sm font-medium text-slate-700 mb-1.5 ml-1">Acquisition Source</label>
                <div className="relative">
                    <div className="absolute left-3 top-3 text-slate-400 group-focus-within:text-emerald-500 transition-colors">
                        <Globe className="w-4 h-4" />
                    </div>
                    <select 
                        className="flex h-10 w-full rounded-xl border border-slate-200 bg-slate-50/50 px-3 pl-9 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all focus:bg-white appearance-none cursor-pointer"
                        value={formData.source}
                        onChange={(e) => setFormData({...formData, source: e.target.value as any})}
                    >
                        <option value="Manual">Manual Entry</option>
                        <option value="Facebook">Facebook Ads</option>
                        <option value="Google">Google Ads</option>
                        <option value="Referral">Referral</option>
                    </select>
                     <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                    </div>
                </div>
            </div>

            {/* Notes */}
            <div className="relative group">
                <div className="flex justify-between items-center mb-1.5 px-1">
                    <label className="block text-sm font-medium text-slate-700 flex items-center gap-2">
                        <FileText className="w-3.5 h-3.5 text-slate-400" /> Notes
                    </label>
                    <button 
                        type="button" 
                        onClick={generateEnrichment}
                        disabled={isGenerating}
                        className="text-xs flex items-center text-indigo-600 hover:text-indigo-700 font-medium bg-indigo-50 px-2 py-1 rounded-full transition-colors hover:bg-indigo-100"
                    >
                        {isGenerating ? <Sparkles className="w-3 h-3 mr-1 animate-spin" /> : <Wand2 className="w-3 h-3 mr-1" />}
                        {isGenerating ? 'Enhancing...' : 'AI Enhance'}
                    </button>
                </div>
                <textarea
                    className="flex w-full rounded-xl border border-slate-200 bg-slate-50/50 px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 min-h-[100px] resize-none transition-all focus:bg-white placeholder:text-slate-400"
                    placeholder="Enter any additional details about the lead..."
                    value={formData.notes}
                    onChange={(e) => setFormData({...formData, notes: e.target.value})}
                />
            </div>
          </div>

          <div className="pt-4 flex justify-end gap-3">
            <Button 
                type="button" 
                variant="ghost" 
                onClick={onClose}
                className="rounded-xl hover:bg-slate-100 text-slate-600"
            >
                Cancel
            </Button>
            <Button 
                type="submit"
                className="rounded-xl bg-slate-900 hover:bg-slate-800 text-white shadow-lg shadow-slate-900/20 px-6"
            >
                Create Profile
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
};
```

To restore the top 4 KPI cards on the Analytics page to the previous, cleaner layout (removing the heavy colored borders and icon backgrounds while retaining the shadow effects), I will update `pages/Analytics.tsx`.

# Updated files:

## pages/Analytics.tsx

Reverted the top 4 KPI cards to the standard, cleaner card design while keeping the colorful charts.

```tsx
import React from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '../components/ui/Card';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend, AreaChart, Area, ComposedChart, Line 
} from 'recharts';
import { Lead } from '../types';
import { DollarSign, TrendingUp, Users, Activity, Target, ArrowUpRight, ArrowDownRight } from 'lucide-react';
import { cn } from '../lib/utils';

interface AnalyticsProps {
  leads: Lead[];
}

export const Analytics: React.FC<AnalyticsProps> = ({ leads }) => {
  // --- Constants & Mock Configurations ---
  const STATUS_VALUES: Record<string, number> = {
    'New': 0,
    'Contacted': 100,
    'Qualified': 1500,
    'Proposal': 5000,
    'Won': 12000,
    'Lost': 0
  };

  const CHANNEL_SPEND: Record<string, number> = {
    'Facebook': 1200,
    'Google': 2500,
    'Manual': 0,
    'Referral': 150
  };

  // Updated to Vibrant/Colorful Palette
  const COLORS = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#f43f5e', '#06b6d4'];
  const ROI_COLORS = { revenue: '#10b981', spend: '#f43f5e' };

  // --- Metrics Calculations ---

  // 1. Total Leads
  const totalLeads = leads.length;

  // 2. Lead Velocity (Mock: Compare last 30 days vs previous 30 days)
  const now = new Date();
  const currentMonth = now.getMonth();
  const leadsThisMonth = leads.filter(l => new Date(l.createdAt).getMonth() === currentMonth).length;
  // Mock previous month data for demo purposes if strictly 0
  const leadsLastMonth = Math.max(Math.floor(leadsThisMonth * 0.8), 1); 
  const velocity = ((leadsThisMonth - leadsLastMonth) / leadsLastMonth) * 100;

  // 3. Pipeline Value (Weighted Forecast)
  const pipelineValue = leads.reduce((acc, lead) => acc + (STATUS_VALUES[lead.status] || 0), 0);
  const actualRevenue = leads.filter(l => l.status === 'Won').reduce((acc, l) => acc + STATUS_VALUES['Won'], 0);

  // 4. Lead Quality (Conversion to Qualified+)
  const qualifiedLeads = leads.filter(l => ['Qualified', 'Proposal', 'Won'].includes(l.status));
  const qualityScore = totalLeads > 0 ? (qualifiedLeads.length / totalLeads) * 100 : 0;

  // --- Chart Data Preparation ---

  // Source Distribution
  const sourceData = leads.reduce((acc, lead) => {
    const existing = acc.find(i => i.name === lead.source);
    if (existing) {
      existing.value += 1;
    } else {
      acc.push({ name: lead.source, value: 1 });
    }
    return acc;
  }, [] as { name: string; value: number }[]);

  // Pipeline Funnel
  const funnelSteps = ['New', 'Contacted', 'Qualified', 'Proposal', 'Won'];
  const funnelData = funnelSteps.map(status => ({
    name: status,
    count: leads.filter(l => l.status === status).length,
    value: leads.filter(l => l.status === status).reduce((acc, l) => acc + STATUS_VALUES[status], 0)
  }));

  // Channel ROI
  const channelRoiData = Object.keys(CHANNEL_SPEND).map(channel => {
    const channelLeads = leads.filter(l => l.source === channel);
    const revenue = channelLeads.filter(l => l.status === 'Won').length * STATUS_VALUES['Won'];
    const spend = CHANNEL_SPEND[channel] || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend) * 100 : 0;
    return {
      name: channel,
      revenue,
      spend,
      roi: Math.round(roi)
    };
  });

  // Volume & Quality Trend (Mocked Time Series for Demo)
  // In a real app, we would group `leads` by createdAt date buckets.
  const volumeTrendData = [
    { name: 'Week 1', total: 12, qualified: 4 },
    { name: 'Week 2', total: 18, qualified: 7 },
    { name: 'Week 3', total: 15, qualified: 6 },
    { name: 'Week 4', total: 24, qualified: 12 },
    { name: 'Current', total: leadsThisMonth || 8, qualified: qualifiedLeads.length || 3 },
  ];

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-3xl font-bold tracking-tight text-slate-900">Analytics</h2>
        <p className="text-slate-500 mt-1">Key performance indicators and detailed reports.</p>
      </div>

      {/* KPI Cards */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card className="shadow-md hover:shadow-lg transition-shadow">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium text-slate-600">Total Leads</CardTitle>
            <Users className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-slate-800">{totalLeads}</div>
            <p className="text-xs text-slate-500 mt-1">Across all sources</p>
          </CardContent>
        </Card>

        <Card className="shadow-md hover:shadow-lg transition-shadow">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium text-slate-600">Lead Velocity</CardTitle>
            <Activity className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold flex items-center text-slate-800">
              {velocity > 0 ? '+' : ''}{Math.round(velocity)}%
              {velocity >= 0 ? (
                <ArrowUpRight className="h-4 w-4 text-emerald-500 ml-1" />
              ) : (
                <ArrowDownRight className="h-4 w-4 text-rose-500 ml-1" />
              )}
            </div>
            <p className="text-xs text-slate-500 mt-1">MoM Growth</p>
          </CardContent>
        </Card>

        <Card className="shadow-md hover:shadow-lg transition-shadow">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium text-slate-600">Pipeline Value</CardTitle>
            <DollarSign className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-slate-800">${(pipelineValue / 1000).toFixed(1)}k</div>
            <p className="text-xs text-slate-500 mt-1">Est. Revenue (Weighted)</p>
          </CardContent>
        </Card>

        <Card className="shadow-md hover:shadow-lg transition-shadow">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium text-slate-600">Lead Quality</CardTitle>
            <Target className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-slate-800">{Math.round(qualityScore)}%</div>
            <p className="text-xs text-slate-500 mt-1">Qualified Rate</p>
          </CardContent>
        </Card>
      </div>

      {/* Main Charts Row */}
      <div className="grid gap-6 md:grid-cols-7">

        {/* Lead Volume & Quality Trend */}
        <Card className="col-span-4 shadow-lg">
          <CardHeader>
            <CardTitle>Lead Volume & Quality</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={volumeTrendData} margin={{ top: 20, right: 20, bottom: 20, left: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} dy={10} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                  <Tooltip 
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                  />
                  <Legend verticalAlign="top" height={36} iconType="circle" />
                  <Bar dataKey="total" name="Total Leads" fill="#6366f1" barSize={32} radius={[6, 6, 0, 0]} />
                  <Line type="monotone" dataKey="qualified" name="Qualified" stroke="#0f172a" strokeWidth={3} dot={{r: 4, fill: '#0f172a'}} />
                </ComposedChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Pipeline Distribution */}
        <Card className="col-span-3 shadow-lg">
          <CardHeader>
            <CardTitle>Pipeline Distribution</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={funnelData} layout="vertical" margin={{ left: 10 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e2e8f0" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={70} tick={{ fontSize: 12, fill: '#64748b' }} axisLine={false} tickLine={false} />
                  <Tooltip 
                    cursor={{ fill: '#f8fafc' }}
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                    formatter={(value: number, name: string) => name === 'value' ? [`$${value}`, 'Est. Value'] : [value, 'Leads']}
                  />
                  <Bar dataKey="count" radius={[0, 6, 6, 0]} barSize={24}>
                    {funnelData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* ROI & Sources Row */}
      <div className="grid gap-6 md:grid-cols-2">

        {/* Channel ROI */}
        <Card className="shadow-lg">
          <CardHeader>
            <CardTitle>Channel ROI & Revenue</CardTitle>
          </CardHeader>
          <CardContent>
             <div className="h-[300px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={channelRoiData} margin={{ top: 20, bottom: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} dy={10} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                  <Tooltip 
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                    formatter={(value: number) => [`$${value}`, '']}
                  />
                  <Legend />
                  <Bar dataKey="spend" name="Ad Spend" fill={ROI_COLORS.spend} radius={[4, 4, 0, 0]} barSize={20} />
                  <Bar dataKey="revenue" name="Revenue" fill={ROI_COLORS.revenue} radius={[4, 4, 0, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Source Breakdown (Pie) */}
        <Card className="shadow-lg">
          <CardHeader>
            <CardTitle>Lead Sources</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[300px] w-full relative">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={sourceData}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={90}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {sourceData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                  />
                  <Legend verticalAlign="middle" align="right" layout="vertical" iconType="circle" />
                </PieChart>
              </ResponsiveContainer>
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none pr-[80px]"> 
                <div className="text-center">
                  <span className="text-3xl font-bold text-slate-900">{totalLeads}</span>
                  <p className="text-xs text-slate-500 uppercase tracking-wide">Leads</p>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

To optimize the Follow Up page for mobile, I will refactor the layout to use a tabbed interface or a responsive grid that stacks gracefully. I will specifically ensure that the "Select Leads / History" panel and the "Message Composer" panel are easily accessible on small screens, likely by allowing the composer to be toggled or stacked below the list.

Here are the changes:
1.  **Responsive Layout**: Switch from a fixed `flex-row` to a `flex-col lg:flex-row`.
2.  **Mobile Navigation**: Ensure the tabs for "Select Leads" and "History" are touch-friendly.
3.  **Composer Visibility**: On mobile, the composer will stack at the bottom or be sticky, ensuring it doesn't get lost.

# Updated files:

## pages/FollowUp.tsx

-   Updated main container to `flex flex-col lg:flex-row`.
-   Adjusted height classes to `h-[calc(100vh-12rem)]` (or similar dynamic height) for desktop, while allowing natural flow on mobile.
-   Made the Composer card full width on mobile and fixed width on desktop.
-   Improved responsive padding and button sizing.

```tsx
import React, { useState, useEffect } from 'react';
import { Lead, MessageLog, MessageChannel } from '../types';
import { Card, CardHeader, CardTitle, CardContent } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';
import { Mail, MessageSquare, Smartphone, Send, Search, CheckSquare, Square, CalendarClock, History, Users, AlertCircle, CheckCircle, Clock, Calendar, Hash, FileText, ChevronLeft, ChevronRight, Filter } from 'lucide-react';
import { cn, formatDate } from '../lib/utils';

interface FollowUpProps {
  leads: Lead[];
  messageLogs: MessageLog[];
  onSendMessage: (leadIds: string[], content: string, channel: MessageChannel, scheduledTime?: string) => void;
  initialSelectedLeadId?: string;
}

const ITEMS_PER_PAGE = 15;

export const FollowUp: React.FC<FollowUpProps> = ({ leads, messageLogs, onSendMessage, initialSelectedLeadId }) => {
  const [activeTab, setActiveTab] = useState<'leads' | 'history'>('leads');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [channel, setChannel] = useState<MessageChannel>('email');
  const [message, setMessage] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSending, setIsSending] = useState(false);

  // Pagination State
  const [leadsPage, setLeadsPage] = useState(1);
  const [historyPage, setHistoryPage] = useState(1);

  // Scheduling state
  const [isScheduled, setIsScheduled] = useState(false);
  const [scheduledTime, setScheduledTime] = useState('');

  // Tooltip state
  const [hoveredLead, setHoveredLead] = useState<Lead | null>(null);
  const [hoveredLog, setHoveredLog] = useState<MessageLog | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  // Handle initial selection from navigation
  useEffect(() => {
    if (initialSelectedLeadId) {
        setSelectedIds(new Set([initialSelectedLeadId]));
        setActiveTab('leads');
    }
  }, [initialSelectedLeadId]);

  // Filter Logic
  const filteredLeads = leads.filter(lead => 
    lead.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    lead.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Reset page on search
  useEffect(() => {
    setLeadsPage(1);
  }, [searchTerm]);

  // Pagination Logic - Leads
  const totalLeadsPages = Math.ceil(filteredLeads.length / ITEMS_PER_PAGE);
  const leadsStartIndex = (leadsPage - 1) * ITEMS_PER_PAGE;
  const paginatedLeads = filteredLeads.slice(leadsStartIndex, leadsStartIndex + ITEMS_PER_PAGE);

  // Pagination Logic - History
