} from 'recharts';
import { Lead } from '../types';
import { DollarSign, TrendingUp, Users, Activity, Target, ArrowUpRight, ArrowDownRight, Download, Loader2 } from 'lucide-react';
import { cn } from '../lib/utils';

interface AnalyticsProps {
  leads: Lead[];
}

export const Analytics: React.FC<AnalyticsProps> = ({ leads }) => {
  const [isDownloading, setIsDownloading] = useState(false);

  // --- Constants & Mock Configurations ---
  const STATUS_VALUES: Record<string, number> = {
    'New': 0,
    'Contacted': 100,
    'Qualified': 1500,
    'Proposal': 5000,
    'Won': 12000,
    'Lost': 0
  };

  const CHANNEL_SPEND: Record<string, number> = {
    'Facebook': 1200,
    'Google': 2500,
    'Manual': 0,
    'Referral': 150
  };

  // Vibrant/Colorful Palette
  const COLORS = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#f43f5e', '#06b6d4'];
  const ROI_COLORS = { revenue: '#10b981', spend: '#f43f5e' };

  // --- Metrics Calculations ---

  // 1. Total Leads
  const totalLeads = leads.length;

  // 2. Lead Velocity (Mock: Compare last 30 days vs previous 30 days)
  const now = new Date();
  const currentMonth = now.getMonth();
  const leadsThisMonth = leads.filter(l => new Date(l.createdAt).getMonth() === currentMonth).length;
  const leadsLastMonth = Math.max(Math.floor(leadsThisMonth * 0.8), 1); 
  const velocity = ((leadsThisMonth - leadsLastMonth) / leadsLastMonth) * 100;

  // 3. Pipeline Value (Weighted Forecast)
  const pipelineValue = leads.reduce((acc, lead) => acc + (STATUS_VALUES[lead.status] || 0), 0);
  const actualRevenue = leads.filter(l => l.status === 'Won').reduce((acc, l) => acc + STATUS_VALUES['Won'], 0);

  // 4. Lead Quality (Conversion to Qualified+)
  const qualifiedLeads = leads.filter(l => ['Qualified', 'Proposal', 'Won'].includes(l.status));
  const qualityScore = totalLeads > 0 ? (qualifiedLeads.length / totalLeads) * 100 : 0;

  // --- Chart Data Preparation ---

  // Source Distribution
  const sourceData = leads.reduce((acc, lead) => {
    const existing = acc.find(i => i.name === lead.source);
    if (existing) {
      existing.value += 1;
    } else {
      acc.push({ name: lead.source, value: 1 });
    }
    return acc;
  }, [] as { name: string; value: number }[]);

  // Pipeline Funnel
  const funnelSteps = ['New', 'Contacted', 'Qualified', 'Proposal', 'Won'];
  const funnelData = funnelSteps.map(status => ({
    name: status,
    count: leads.filter(l => l.status === status).length,
    value: leads.filter(l => l.status === status).reduce((acc, l) => acc + STATUS_VALUES[status], 0)
  }));

  // Channel ROI
  const channelRoiData = Object.keys(CHANNEL_SPEND).map(channel => {
    const channelLeads = leads.filter(l => l.source === channel);
    const revenue = channelLeads.filter(l => l.status === 'Won').length * STATUS_VALUES['Won'];
    const spend = CHANNEL_SPEND[channel] || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend) * 100 : 0;
    return {
      name: channel,
      revenue,
      spend,
      roi: Math.round(roi)
    };
