interface AnalyticsProps {
  leads: Lead[];
}

export const Analytics: React.FC<AnalyticsProps> = ({ leads }) => {
  const [isDownloading, setIsDownloading] = useState(false);

  // --- Constants & Mock Configurations ---
  const STATUS_VALUES: Record<string, number> = {
    'New': 0,
    'Contacted': 100,
    'Qualified': 1500,
    'Proposal': 5000,
    'Won': 12000,
    'Lost': 0
  };

  const CHANNEL_SPEND: Record<string, number> = {
    'Facebook': 1200,
    'Google': 2500,
    'Manual': 0,
    'Referral': 150
  };

  // Vibrant/Colorful Palette
  const COLORS = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#f43f5e', '#06b6d4'];
  const ROI_COLORS = { revenue: '#10b981', spend: '#f43f5e' };

  // --- Metrics Calculations ---

  // 1. Total Leads
  const totalLeads = leads.length;

  // 2. Lead Velocity (Mock: Compare last 30 days vs previous 30 days)
  const now = new Date();
  const currentMonth = now.getMonth();
  const leadsThisMonth = leads.filter(l => new Date(l.createdAt).getMonth() === currentMonth).length;
  const leadsLastMonth = Math.max(Math.floor(leadsThisMonth * 0.8), 1); 
  const velocity = ((leadsThisMonth - leadsLastMonth) / leadsLastMonth) * 100;

  // 3. Pipeline Value (Weighted Forecast)
  const pipelineValue = leads.reduce((acc, lead) => acc + (STATUS_VALUES[lead.status] || 0), 0);
  const actualRevenue = leads.filter(l => l.status === 'Won').reduce((acc, l) => acc + STATUS_VALUES['Won'], 0);

  // 4. Lead Quality (Conversion to Qualified+)
  const qualifiedLeads = leads.filter(l => ['Qualified', 'Proposal', 'Won'].includes(l.status));
  const qualityScore = totalLeads > 0 ? (qualifiedLeads.length / totalLeads) * 100 : 0;

  // --- Chart Data Preparation ---

  // Source Distribution
  const sourceData = leads.reduce((acc, lead) => {
    const existing = acc.find(i => i.name === lead.source);
    if (existing) {
      existing.value += 1;
    } else {
      acc.push({ name: lead.source, value: 1 });
    }
    return acc;
  }, [] as { name: string; value: number }[]);

  // Pipeline Funnel
  const funnelSteps = ['New', 'Contacted', 'Qualified', 'Proposal', 'Won'];
  const funnelData = funnelSteps.map(status => ({
    name: status,
    count: leads.filter(l => l.status === status).length,
    value: leads.filter(l => l.status === status).reduce((acc, l) => acc + STATUS_VALUES[status], 0)
  }));

  // Channel ROI
  const channelRoiData = Object.keys(CHANNEL_SPEND).map(channel => {
    const channelLeads = leads.filter(l => l.source === channel);
    const revenue = channelLeads.filter(l => l.status === 'Won').length * STATUS_VALUES['Won'];
    const spend = CHANNEL_SPEND[channel] || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend) * 100 : 0;
    return {
      name: channel,
      revenue,
      spend,
      roi: Math.round(roi)
    };
  });

  // Volume & Quality Trend
  const volumeTrendData = [
    { name: 'Week 1', total: 12, qualified: 4 },
    { name: 'Week 2', total: 18, qualified: 7 },
    { name: 'Week 3', total: 15, qualified: 6 },
    { name: 'Week 4', total: 24, qualified: 12 },
    { name: 'Current', total: leadsThisMonth || 8, qualified: qualifiedLeads.length || 3 },
  ];

  // --- CSV Export Logic ---
  const handleDownloadReport = () => {
    setIsDownloading(true);

    setTimeout(() => {
        // 1. Define CSV Headers & Data
        const headers = ['Report Generated', new Date().toLocaleString(), '', ''];

        // Section: KPIs
        const kpiRows = [
            ['METRIC', 'VALUE', 'NOTES'],
            ['Total Leads', totalLeads, 'All time'],
            ['Lead Velocity', `${Math.round(velocity)}%`, 'Month over Month growth'],
            ['Pipeline Value', `$${pipelineValue}`, 'Estimated weighted value'],
            ['Lead Quality Score', `${Math.round(qualityScore)}%`, 'Conversion to Qualified+'],
            ['', '', ''] // Spacer
        ];

        // Section: Pipeline Breakdown
        const pipelineRows = [
            ['PIPELINE STAGE', 'LEAD COUNT', 'ESTIMATED VALUE'],
            ...funnelData.map(d => [d.name, d.count, `$${d.value}`]),
            ['', '', ''] // Spacer
        ];

        // Section: Channel Performance
        const channelRows = [
            ['CHANNEL', 'REVENUE', 'AD SPEND', 'ROI %'],
            ...channelRoiData.map(d => [d.name, `$${d.revenue}`, `$${d.spend}`, `${d.roi}%`]),
            ['', '', ''] // Spacer
        ];

        // Combine all rows
        const csvArray = [headers, ...kpiRows, ...pipelineRows, ...channelRows];

        // Convert to CSV String
        const csvContent = csvArray.map(e => e.join(",")).join("\n");

        // Trigger Download using Blob (More robust than encodeURI)
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);

        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `levrix_analytics_report_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

        setIsDownloading(false);
    }, 1000); // Fake delay for UX
  };

  return (
    <div className="space-y-6">
