import { ChevronLeft, ChevronRight, MessageSquare, Phone, Clock, Calendar as CalendarIcon, MoreHorizontal } from 'lucide-react';
import { Lead, MessageLog } from '../types';
import { cn } from '../lib/utils';

interface CalendarProps {
  leads: Lead[];
  messageLogs: MessageLog[];
}

export const Calendar: React.FC<CalendarProps> = ({ leads, messageLogs }) => {
  const [currentDate, setCurrentDate] = useState(new Date());

  // Helper to get days in month
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month + 1, 0).getDate();
  };

  // Helper to get start day of week (0-6)
  const getFirstDayOfMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month, 1).getDay();
  };

  const prevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  // --- Data Aggregation ---
  // Get all scheduled items for the current month
  const getEventsForDay = (day: number) => {
    const targetDateStr = new Date(currentDate.getFullYear(), currentDate.getMonth(), day).toDateString();

    const events: { id: string, type: 'followup' | 'message', title: string, time?: string, status?: string }[] = [];

    // 1. Leads with Next Follow Up
    leads.forEach(lead => {
        if (lead.nextFollowUp) {
            const d = new Date(lead.nextFollowUp);
            if (d.toDateString() === targetDateStr) {
                events.push({
                    id: `lead-${lead.id}`,
                    type: 'followup',
                    title: `Call: ${lead.name}`,
                    time: d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                });
            }
        }
    });

    // 2. Scheduled Messages
    messageLogs.forEach(log => {
        if (log.scheduledAt) {
            const d = new Date(log.scheduledAt);
            if (d.toDateString() === targetDateStr) {
                events.push({
                    id: `msg-${log.id}`,
                    type: 'message',
                    title: `${log.channel.toUpperCase()} to ${log.leadName}`,
                    time: d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                    status: log.status
                });
            }
        }
    });

    return events;
  };

  const daysInMonth = getDaysInMonth(currentDate);
  const startDay = getFirstDayOfMonth(currentDate);
  const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const emptyDays = Array.from({ length: startDay }, (_, i) => i);

  const monthName = currentDate.toLocaleString('default', { month: 'long' });
  const year = currentDate.getFullYear();

  return (
    <div className="space-y-6 h-full flex flex-col">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold tracking-tight text-slate-900">Calendar</h2>
          <p className="text-slate-500 mt-1">Schedule and view upcoming tasks and messages.</p>
        </div>
        <div className="flex items-center gap-4 bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm">
            <Button variant="ghost" size="sm" onClick={prevMonth} className="h-8 w-8 p-0 rounded-lg">
                <ChevronLeft className="w-5 h-5 text-slate-600" />
            </Button>
            <span className="text-sm font-bold text-slate-900 w-32 text-center select-none">
                {monthName} {year}
            </span>
            <Button variant="ghost" size="sm" onClick={nextMonth} className="h-8 w-8 p-0 rounded-lg">
                <ChevronRight className="w-5 h-5 text-slate-600" />
            </Button>
        </div>
      </div>

      <Card className="flex-1 flex flex-col overflow-hidden border-0 shadow-lg">
        <div className="grid grid-cols-7 border-b border-slate-100 bg-slate-50">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                <div key={day} className="py-3 text-center text-xs font-semibold text-slate-500 uppercase tracking-wider">
                    {day}
                </div>
            ))}
        </div>
        <div className="grid grid-cols-7 flex-1 auto-rows-fr bg-slate-100 gap-px border-b border-slate-100">
            {/* Empty cells for previous month */}
            {emptyDays.map(i => (
                <div key={`empty-${i}`} className="bg-slate-50/30 min-h-[120px]" />
            ))}

            {/* Days of current month */}
            {days.map(day => {
                const events = getEventsForDay(day);
                const isToday = new Date().toDateString() === new Date(year, currentDate.getMonth(), day).toDateString();

                return (
                    <div key={day} className={cn("bg-white p-3 min-h-[120px] group transition-colors hover:bg-slate-50/50 flex flex-col gap-1 relative", isToday && "bg-blue-50/30")}>
                        <div className="flex justify-between items-start mb-1">
                            <span className={cn(
                                "text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full transition-colors", 
                                isToday ? "bg-blue-600 text-white shadow-md shadow-blue-200" : "text-slate-700 group-hover:bg-slate-100"
                            )}>
                                {day}
                            </span>
                            {/* Add Event Button (Hidden by default, shown on hover) */}
                            <button className="opacity-0 group-hover:opacity-100 p-1 text-slate-400 hover:text-slate-600 transition-opacity">
                                <MoreHorizontal className="w-4 h-4" />
                            </button>
                        </div>

                        <div className="flex-1 flex flex-col gap-1 overflow-y-auto max-h-[100px] no-scrollbar">
                            {events.map((event, idx) => (
                                <div 
                                    key={idx} 
                                    className={cn(
                                        "text-[10px] px-2 py-1.5 rounded-md border truncate font-medium flex items-center gap-1.5 transition-shadow hover:shadow-sm cursor-pointer",
                                        event.type === 'followup' 
                                            ? "bg-amber-50 text-amber-800 border-amber-100 hover:border-amber-200" 
                                            : "bg-emerald-50 text-emerald-800 border-emerald-100 hover:border-emerald-200"
                                    )}
                                    title={event.title}
                                >
                                    {event.type === 'followup' ? <Phone className="w-3 h-3 flex-shrink-0" /> : <MessageSquare className="w-3 h-3 flex-shrink-0" />}
                                    <span className="truncate flex-1">{event.title}</span>
                                    {event.time && <span className="opacity-70 text-[9px]">{event.time}</span>}
                                </div>
                            ))}
                        </div>
                    </div>
                );
            })}

            {/* Fill remaining grid to keep shape */}
            {Array.from({ length: 42 - (daysInMonth + startDay) }).map((_, i) => (
                 <div key={`next-empty-${i}`} className="bg-slate-50/30 min-h-[120px]" />
            ))}
        </div>
      </Card>
    </div>
  );
};
