}

const ITEMS_PER_PAGE = 15;

export const FollowUp: React.FC<FollowUpProps> = ({ leads, messageLogs, onSendMessage, initialSelectedLeadId }) => {
  const [activeTab, setActiveTab] = useState<'leads' | 'history'>('leads');
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [channel, setChannel] = useState<MessageChannel>('email');
  const [message, setMessage] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSending, setIsSending] = useState(false);

  // Pagination State
  const [leadsPage, setLeadsPage] = useState(1);
  const [historyPage, setHistoryPage] = useState(1);

  // Scheduling state
  const [isScheduled, setIsScheduled] = useState(false);
  const [scheduledTime, setScheduledTime] = useState('');

  // Tooltip state (Desktop)
  const [hoveredLead, setHoveredLead] = useState<Lead | null>(null);
  const [hoveredLog, setHoveredLog] = useState<MessageLog | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  // Mobile Expansion State
  const [expandedLeadId, setExpandedLeadId] = useState<string | null>(null);
  const [expandedLogId, setExpandedLogId] = useState<string | null>(null);

  // Handle initial selection from navigation
  useEffect(() => {
    if (initialSelectedLeadId) {
        setSelectedIds(new Set([initialSelectedLeadId]));
        setActiveTab('leads');
        setViewMode('list');
    }
  }, [initialSelectedLeadId]);

  // Filter Logic
  const filteredLeads = leads.filter(lead => 
    lead.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    lead.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Reset page on search
  useEffect(() => {
    setLeadsPage(1);
  }, [searchTerm]);

  // Pagination Logic - Leads
  const totalLeadsPages = Math.ceil(filteredLeads.length / ITEMS_PER_PAGE);
  const leadsStartIndex = (leadsPage - 1) * ITEMS_PER_PAGE;
  const paginatedLeads = filteredLeads.slice(leadsStartIndex, leadsStartIndex + ITEMS_PER_PAGE);

  // Pagination Logic - History
  const totalHistoryPages = Math.ceil(messageLogs.length / ITEMS_PER_PAGE);
  const historyStartIndex = (historyPage - 1) * ITEMS_PER_PAGE;
  const paginatedHistory = messageLogs.slice(historyStartIndex, historyStartIndex + ITEMS_PER_PAGE);


  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredLeads.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredLeads.map(l => l.id)));
    }
  };

  const toggleLeadExpansion = (id: string, e: React.MouseEvent) => {
    // Prevent expansion when clicking checkbox
    if ((e.target as HTMLElement).closest('.checkbox-area')) return;

    // Only toggle on mobile/tablet widths where tooltips are hidden
    if (window.innerWidth < 768) {
        setExpandedLeadId(prev => prev === id ? null : id);
    }
  };

  const toggleLogExpansion = (id: string) => {
    // Only toggle on mobile/tablet
     if (window.innerWidth < 768) {
        setExpandedLogId(prev => prev === id ? null : id);
     }
  };

  const handleSend = () => {
    if (selectedIds.size === 0 || !message.trim()) return;
    if (isScheduled && !scheduledTime) return;

    setIsSending(true);

    // Simulate API delay
    setTimeout(() => {
        onSendMessage(Array.from(selectedIds), message, channel, isScheduled ? scheduledTime : undefined);

        setIsSending(false);
        setMessage('');
        setSelectedIds(new Set());
        setIsScheduled(false);
        setScheduledTime('');

        // Switch to history view to show the new logs
        if (viewMode === 'list') {
            setActiveTab('history');
            setHistoryPage(1); 
        }
    }, 800);
  };

  const insertVariable = (variable: string) => {
    setMessage(prev => prev + ` {${variable}}`);
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
        case 'Delivered': return <CheckCircle className="w-4 h-4 text-emerald-500" />;
        case 'Failed': return <AlertCircle className="w-4 h-4 text-rose-500" />;
        case 'Queued': return <CalendarClock className="w-4 h-4 text-amber-500" />;
        default: return <Clock className="w-4 h-4 text-blue-500" />;
    }
  };

  const getStatusColor = (status: string) => {
      switch (status) {
          case 'Delivered': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
          case 'Failed': return 'bg-rose-50 text-rose-700 border-rose-200';
          case 'Queued': return 'bg-amber-50 text-amber-700 border-amber-200';
          default: return 'bg-blue-50 text-blue-700 border-blue-200';
      }
  };

  // Smart Tooltip Positioning
  const getSmartTooltipStyle = (x: number, y: number): React.CSSProperties => {
    const OFFSET = 16;
    const TOOLTIP_WIDTH = 280; 
    const TOOLTIP_HEIGHT = 220; // approximate max height

    if (typeof window !== 'undefined') {
        const winW = window.innerWidth;
        const winH = window.innerHeight;

        let left = x + OFFSET;
        let top = y + OFFSET;

        // Flip left if too close to right edge
        if (left + TOOLTIP_WIDTH > winW) {
            left = x - TOOLTIP_WIDTH - OFFSET;
        }

        // Flip up if too close to bottom edge
        if (top + TOOLTIP_HEIGHT > winH) {
            top = y - TOOLTIP_HEIGHT - OFFSET;
        }

        return { top, left };
    }
    return { top: y + OFFSET, left: x + OFFSET };
  };

  return (
    <div className="space-y-4 md:space-y-6 h-full flex flex-col pb-20 md:pb-0">

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-2xl md:text-3xl font-bold tracking-tight text-slate-900">Follow Ups</h2>
            <p className="text-slate-500 mt-1 text-sm md:text-base">Manage your scheduled calls, emails, and meetings.</p>
          </div>
          <Button 
            variant="outline" 
            className="hidden sm:flex bg-white w-full md:w-auto"
            onClick={() => setViewMode(prev => prev === 'list' ? 'calendar' : 'list')}
