              {viewMode === 'list' ? <Calendar className="w-4 h-4 mr-2" /> : <List className="w-4 h-4 mr-2" />}
              {viewMode === 'list' ? 'Calendar View' : 'List View'}
          </Button>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-4">
        <div className="bg-rose-50 border border-rose-100 rounded-2xl p-4 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-full bg-rose-100 flex items-center justify-center text-rose-600">
                    <AlertCircle className="w-5 h-5" />
                </div>
                <div>
                    <div className="text-sm font-medium text-rose-900">Overdue</div>
                    <div className="text-xl md:text-2xl font-bold text-rose-700">0</div>
                </div>
            </div>
        </div>

         <div className="bg-amber-50 border border-amber-100 rounded-2xl p-4 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-full bg-amber-100 flex items-center justify-center text-amber-600">
                    <Clock className="w-5 h-5" />
                </div>
                <div>
                    <div className="text-sm font-medium text-amber-900">Due Today</div>
                    <div className="text-xl md:text-2xl font-bold text-amber-700">0</div>
                </div>
            </div>
        </div>

         <div className="bg-emerald-50 border border-emerald-100 rounded-2xl p-4 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-600">
                    <CheckCircle className="w-5 h-5" />
                </div>
                <div>
                    <div className="text-sm font-medium text-emerald-900">Upcoming</div>
                    <div className="text-xl md:text-2xl font-bold text-emerald-700">0</div>
                </div>
            </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row md:items-center justify-between bg-white p-3 rounded-2xl border border-slate-200 shadow-sm gap-3">
         <div className="flex flex-wrap items-center gap-2">
            <Filter className="w-4 h-4 text-slate-400 ml-1" />
            <span className="text-sm font-medium text-slate-700 mr-1 hidden md:inline">Filters:</span>

            <select className="text-sm border-none bg-slate-50 rounded-lg px-3 py-1.5 text-slate-600 focus:ring-0 cursor-pointer hover:bg-slate-100 transition-colors w-full md:w-auto">
                <option>All Statuses</option>
                <option>New</option>
                <option>Contacted</option>
            </select>

            <select className="text-sm border-none bg-slate-50 rounded-lg px-3 py-1.5 text-slate-600 focus:ring-0 cursor-pointer hover:bg-slate-100 transition-colors w-full md:w-auto">
                <option>All Channels</option>
                <option>Email</option>
                <option>SMS</option>
            </select>
         </div>
         <div className="text-xs text-slate-400 md:mr-2 text-center md:text-right">
             {viewMode === 'list' && `Showing ${activeTab === 'leads' ? paginatedLeads.length : paginatedHistory.length} tasks`}
         </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-6 h-auto lg:h-[calc(100vh-340px)] min-h-[500px]">

        {/* Left Column: Lead Selection or History or Calendar */}
