  const [integrations, setIntegrations] = useState<Integrations>(DEFAULT_INTEGRATIONS);
  const [teamMembers, setTeamMembers] = useState<TeamMember[]>([]);
  const [loading, setLoading] = useState(true);

  // Navigation State for passing data between pages
  const [navData, setNavData] = useState<any>(null);

  // Setup State for manual config
  // Pre-fill the URL you provided
  const [setupUrl, setSetupUrl] = useState('https://orpsewzolrqyzrylvghs.supabase.co');
  const [setupKey, setSetupKey] = useState('');

  // --- Auth & Initial Data Fetching ---
  useEffect(() => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    // Check active session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch Data & Subscribe to Realtime when Session exists
  useEffect(() => {
    if (session?.user) {
      fetchLeads();
      fetchLogs();
      fetchProfile();

      // Initialize Team with current user
      if (teamMembers.length === 0) {
          setTeamMembers([{
              id: session.user.id,
              email: session.user.email,
              name: 'You',
              role: 'Admin',
              status: 'Active',
              joinedAt: new Date().toISOString()
          }]);
      }

      // Realtime Subscription for Leads
      const channel = supabase
        .channel('leads-changes')
        .on(
          'postgres_changes',
          {
            event: '*', // Listen to INSERT, UPDATE, DELETE
            schema: 'public',
            table: 'leads',
            filter: `user_id=eq.${session.user.id}` // Only listen to my leads
          },
          (payload) => {
            // Handle different event types
            if (payload.eventType === 'INSERT') {
                const newLead = mapDbLead(payload.new);
                setLeads((prev) => [newLead, ...prev]);
            } else if (payload.eventType === 'UPDATE') {
                const updatedLead = mapDbLead(payload.new);
                setLeads((prev) => prev.map((lead) => lead.id === updatedLead.id ? updatedLead : lead));
            } else if (payload.eventType === 'DELETE') {
                setLeads((prev) => prev.filter((lead) => lead.id !== payload.old.id));
            }
          }
        )
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, [session]);

  const fetchLeads = async () => {
    try {
      const { data, error } = await supabase
        .from('leads')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;

      // Map snake_case DB to camelCase Frontend
      const mappedLeads: Lead[] = (data || []).map(mapDbLead);
      setLeads(mappedLeads);
    } catch (error: any) {
      // Graceful fallback - Likely table doesn't exist yet
      console.warn('Database not ready, switching to Mock Leads:', error.message);
      setLeads(INITIAL_LEADS);
    }
  };

  const fetchLogs = async () => {
    try {
      const { data, error } = await supabase
        .from('message_logs')
        .select('*')
        .order('sent_at', { ascending: false });

      if (error) throw error;

      const mappedLogs: MessageLog[] = (data || []).map((l: any) => ({
        id: l.id,
        leadId: l.lead_id,
        leadName: l.lead_name,
        channel: l.channel,
        status: l.status,
        content: l.content,
        sentAt: l.sent_at,
        scheduledAt: l.scheduled_at
      }));
      setMessageLogs(mappedLogs);
    } catch (error: any) {
      // Graceful fallback
      console.warn('Database not ready, switching to Mock Logs:', error.message);
      setMessageLogs(INITIAL_LOGS);
    }
  };

  const fetchProfile = async () => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('integrations')
        .eq('id', session.user.id)
        .single();

      if (data && data.integrations) {
        // Merge with default to ensure new keys exist
        setIntegrations({ ...DEFAULT_INTEGRATIONS, ...data.integrations });
      } else if (error && error.code !== 'PGRST116') {
        throw error;
      }
    } catch (error: any) {
       // Graceful fallback - just keep default integrations
       console.warn('Database not ready, using Default Settings:', error.message);
       setIntegrations(DEFAULT_INTEGRATIONS);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setSession(null);
    setLeads([]);
    setMessageLogs([]);
  };

  const handleSaveConfig = () => {
    if (setupUrl && setupKey) {
        window.localStorage.setItem('sb_url', setupUrl);
        window.localStorage.setItem('sb_key', setupKey);
        window.location.reload();
    }
  };

  const handleNavigate = (page: string, data?: any) => {
    setActivePage(page);
    if (data) {
        setNavData(data);
    }
  };

  // --- Actions ---

  const handleAddLead = async (newLeadData: Omit<Lead, 'id' | 'createdAt'>) => {
    if (!session?.user) return;

    try {
      const dbLead = {
        user_id: session.user.id,
        name: newLeadData.name,
        email: newLeadData.email,
        phone: newLeadData.phone,
        source: newLeadData.source,
        status: newLeadData.status,
        notes: newLeadData.notes
      };

      const { data, error } = await supabase
        .from('leads')
        .insert([dbLead])
        .select()
        .single();

      if (error) throw error;

    } catch (error: any) {
      console.warn('Failed to save to DB (using local fallback):', error.message);
      // Fallback: Add to local state manually if DB fails
      const mockNewLead: Lead = {
          ...newLeadData,
          id: Math.random().toString(36).substr(2, 9),
          createdAt: new Date().toISOString(),
          user_id: session.user.id
      };
      setLeads(prev => [mockNewLead, ...prev]);
    }
  };

  const handleUpdateLead = async (updatedLead: Lead) => {
    try {
      const { error } = await supabase
        .from('leads')
        .update({
          name: updatedLead.name,
          email: updatedLead.email,
          phone: updatedLead.phone,
          status: updatedLead.status,
          source: updatedLead.source,
          notes: updatedLead.notes
        })
        .eq('id', updatedLead.id);

      if (error) throw error;

      // Optimistic update for local state (Realtime might also trigger, but this ensures responsiveness)
      setLeads(prev => prev.map(l => l.id === updatedLead.id ? updatedLead : l));

    } catch (error: any) {
      console.warn('Failed to update DB (using local fallback):', error.message);
      // Fallback local update
      setLeads(prev => prev.map(l => l.id === updatedLead.id ? updatedLead : l));
    }
  };

  const handleUpdateStatus = async (id: string, status: LeadStatus) => {
    try {
      const { error } = await supabase
        .from('leads')
        .update({ status })
        .eq('id', id);

      if (error) throw error;
    } catch (error: any) {
      console.warn('Failed to update DB (using local fallback):', error.message);
      // Fallback local update
      setLeads(prev => prev.map(l => l.id === id ? { ...l, status } : l));
    }
  };

  // New function for bulk scheduling reminders without sending messages
  const handleBulkSchedule = async (leadIds: string[], date: string) => {
    try {
      const { error } = await supabase
        .from('leads')
        .update({ next_follow_up: date })
        .in('id', leadIds);

      if (error) throw error;

      // Optimistic Update
      setLeads(prev => prev.map(l => leadIds.includes(l.id) ? { ...l, nextFollowUp: date } : l));

    } catch (error: any) {
        console.warn('Failed to bulk update DB (using local fallback):', error.message);
        setLeads(prev => prev.map(l => leadIds.includes(l.id) ? { ...l, nextFollowUp: date } : l));
    }
  };

  const handleSendMessage = async (
      selectedLeadIds: string[], 
      content: string, 
      channel: MessageChannel, 
      scheduledTime?: string
  ) => {
    if (!session?.user) return;

    const newLogsPayload = selectedLeadIds.map(id => {
        const lead = leads.find(l => l.id === id);
        return {
            user_id: session.user.id,
            lead_id: id,
            lead_name: lead?.name || 'Unknown',
            channel,
            content,
            status: scheduledTime ? 'Queued' : 'Sent',
            scheduled_at: scheduledTime || null
        };
    });

    try {
      const { data, error } = await supabase
        .from('message_logs')
        .insert(newLogsPayload)
        .select();

      if (error) throw error;

      if (data) {
        const mappedNewLogs: MessageLog[] = data.map((l: any) => ({
           id: l.id,
           leadId: l.lead_id,
           leadName: l.lead_name,
           channel: l.channel,
           status: l.status,
           content: l.content,
           sentAt: l.sent_at,
           scheduledAt: l.scheduled_at
        }));
        setMessageLogs(prev => [...mappedNewLogs, ...prev]);
      }
    } catch (error: any) {
      console.warn('Failed to save logs to DB (using local fallback):', error.message);
      // Fallback local update
       const fallbackLogs: MessageLog[] = newLogsPayload.map((l: any, i) => ({
           id: Math.random().toString(),
           leadId: l.lead_id,
           leadName: l.lead_name,
           channel: l.channel,
           status: l.status,
           content: l.content,
           sentAt: new Date().toISOString(),
           scheduledAt: l.scheduled_at
        }));
      setMessageLogs(prev => [...fallbackLogs, ...prev]);
    }
  };

  const handleUpdateIntegrations = async (newIntegrations: Integrations) => {
    setIntegrations(newIntegrations);

    if (!session?.user) return;

    try {
      // Upsert profile
      const { error } = await supabase
        .from('profiles')
        .upsert({ 
          id: session.user.id, 
          email: session.user.email,
          integrations: newIntegrations 
        });

      if (error) throw error;
    } catch (error: any) {
      console.warn('Failed to save settings to DB (keeping local state):', error.message);
    }
  };

  const handleInviteMember = async (email: string, role: 'Admin' | 'Agent' | 'Viewer') => {
      // In a real app, this would call supabase.auth.admin.inviteUserByEmail (backend)
      // or insert into a 'team_invites' table.
      // Here we simulate adding to the local state.
      const newMember: TeamMember = {
          id: Math.random().toString(36).substring(7),
          email,
          name: email.split('@')[0], // placeholder name
          role,
          status: 'Pending',
          joinedAt: new Date().toISOString()
      };
      setTeamMembers(prev => [...prev, newMember]);
  };

  const handleRemoveMember = (id: string) => {
      setTeamMembers(prev => prev.filter(m => m.id !== id));
  };

  if (!isSupabaseConfigured) {
    return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
            <Card className="w-full max-w-md">
                <CardHeader>
                    <CardTitle className="text-xl">Connect to Supabase</CardTitle>
                    <p className="text-sm text-slate-500">
                        Please enter your Supabase <strong>anon public key</strong> to proceed.
                    </p>
                </CardHeader>
                <CardContent className="space-y-4">
                    <Input 
                        label="Project URL" 
                        placeholder="https://xyz.supabase.co" 
                        value={setupUrl}
                        onChange={e => setSetupUrl(e.target.value)}
                    />
                    <Input 
                        label="Anon API Key" 
                        placeholder="eyJhbG..." 
                        type="password"
                        value={setupKey}
                        onChange={e => setSetupKey(e.target.value)}
                    />
                    <div className="text-xs text-slate-500 bg-slate-100 p-2 rounded">
                        Note: You provided a URL as your key. Please find the correct key starting with "ey..." in your Supabase Dashboard.
                    </div>
                    <Button className="w-full" onClick={handleSaveConfig} disabled={!setupUrl || !setupKey}>
                        Save & Connect
                    </Button>
                </CardContent>
            </Card>
        </div>
    );
  }

  if (loading) {
    return (
      <div className="h-screen w-screen flex items-center justify-center bg-slate-50">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-slate-900"></div>
      </div>
    );
  }

  if (!session) {
    return <Login />;
  }

  const renderContent = () => {
    switch (activePage) {
      case 'dashboard':
        return <Dashboard leads={leads} />;
      case 'leads':
        return (
            <Leads 
                leads={leads} 
                onAddLead={handleAddLead} 
                onUpdateStatus={handleUpdateStatus} 
                onUpdateLead={handleUpdateLead}
                onNavigateToFollowUp={(leadId) => handleNavigate('followup', { selectedLeadId: leadId })}
            />
        );
      case 'calendar':
        return <Calendar leads={leads} messageLogs={messageLogs} />;
      case 'analytics':
        return <Analytics leads={leads} />;
      case 'settings':
        return (
            <Settings 
                integrations={integrations} 
                onUpdate={handleUpdateIntegrations}
                teamMembers={teamMembers}
                onInviteMember={handleInviteMember}
                onRemoveMember={handleRemoveMember}
            />
        );
      case 'followup':
        return (
            <FollowUp 
                leads={leads} 
                messageLogs={messageLogs} 
                onSendMessage={handleSendMessage} 
                onScheduleFollowUp={handleBulkSchedule}
                initialSelectedLeadId={navData?.selectedLeadId}
            />
        );
      default:
        return <Dashboard leads={leads} />;
    }
  };

  return (
    <Layout 
        activePage={activePage} 
        onNavigate={(page) => handleNavigate(page)} 
        onLogout={handleLogout}
        userEmail={session.user.email}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;
